function it_inventory_allotment_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('it_inventory_allotment_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'username' => parseCode('<%%creatorUsername%%>', true),
		'select_employee' => Request::lookup('select_employee', ''),
		'department' => Request::val('department', ''),
		'date' => Request::dateComponents('date', '1'),
		'inventory_details' => br2nl(Request::val('inventory_details', '')),
		'purpose' => br2nl(Request::val('purpose', '')),
		'alloted_by' => Request::lookup('alloted_by', ''),
		'allotment_status' => Request::val('allotment_status', 'Pending to allot'),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'approval_remarks' => br2nl(Request::val('approval_remarks', '')),
		'return_status' => Request::val('return_status', 'Not Returned'),
		'returned_date' => Request::dateComponents('returned_date', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('it_inventory_allotment_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		it_inventory_allotment_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function it_inventory_allotment_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function it_inventory_allotment_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('it_inventory_allotment_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: it_inventory_allotment_table_before_delete
	if(function_exists('it_inventory_allotment_table_before_delete')) {
		$args = [];
		if(!it_inventory_allotment_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `it_inventory_allotment_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: it_inventory_allotment_table_after_delete
	if(function_exists('it_inventory_allotment_table_after_delete')) {
		$args = [];
		it_inventory_allotment_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='it_inventory_allotment_table' AND `pkValue`='{$selected_id}'", $eo);
}

function it_inventory_allotment_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('it_inventory_allotment_table', $selected_id, 'edit')) return false;

	$data = [
		'select_employee' => Request::lookup('select_employee', ''),
		'department' => Request::val('department', ''),
		'date' => Request::dateComponents('date', ''),
		'inventory_details' => br2nl(Request::val('inventory_details', '')),
		'purpose' => br2nl(Request::val('purpose', '')),
		'alloted_by' => Request::lookup('alloted_by', ''),
		'allotment_status' => Request::val('allotment_status', ''),
		'approval_status' => Request::val('approval_status', ''),
		'approval_remarks' => br2nl(Request::val('approval_remarks', '')),
		'return_status' => Request::val('return_status', ''),
		'returned_date' => Request::dateComponents('returned_date', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('it_inventory_allotment_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: it_inventory_allotment_table_before_update
	if(function_exists('it_inventory_allotment_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!it_inventory_allotment_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'it_inventory_allotment_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="it_inventory_allotment_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('it_inventory_allotment_table', $data['selectedID'], calculated_fields()['it_inventory_allotment_table']);

	// hook: it_inventory_allotment_table_after_update
	if(function_exists('it_inventory_allotment_table_after_update')) {
		if($row = getRecord('it_inventory_allotment_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!it_inventory_allotment_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('it_inventory_allotment_table', $selected_id);
}

