	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('it_inventory_allotment_table');
	if($hasSelectedId) {
		$jdata = get_joined_record('it_inventory_allotment_table', $selectedId);
		if($jdata === false) $jdata = get_defaults('it_inventory_allotment_table');
		$rdata = $row;
	}
	$templateCode .= loadView('it_inventory_allotment_table-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: it_inventory_allotment_table_dv
	if(function_exists('it_inventory_allotment_table_dv')) {
		$args = [];
		it_inventory_allotment_table_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}